+  always @(posedge clk or negedge rst_n)
     if (!rst_n)
       count <= 16'h0000;
     else if (enable)

before_code:
module sync_counter(
  input clk,
  input rst_n,
  input enable,
  output reg [15:0] count
);

  always @(posedge clk)
    if (!rst_n)
      count <= 16'h0000;
    else if (enable)
      count <= count + 1'b1;

endmodule

after_code:
module sync_counter(
  input clk,
  input rst_n,
  input enable,
  output reg [15:0] count
);

  always @(posedge clk or negedge rst_n)
    if (!rst_n)
      count <= 16'h0000;
    else if (enable)
      count <= count + 1'b1;

endmodule
